PORT = 8787


def _log(entry):
    AUDIT_LOG.insert(0, {
        "ts": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        **entry
    })

class AMLHandler(BaseHTTPRequestHandler):
    protocol_version = 'HTTP/1.1'  # keep-alive
    timeout = 30  # 30s timeout per request

    def log_message(self, fmt, *args):
        pass  # suppress default access log

    def _send(self, data, status=200):
        try:
            body = json.dumps(data, default=str).encode()
            self.send_response(status)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", len(body))
            self.send_header("Connection", "close")
            self.send_header("Access-Control-Allow-Origin", "*")
            self.send_header("Access-Control-Allow-Methods", "GET,POST,OPTIONS")
            self.send_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
            self.send_header("Access-Control-Allow-Credentials", "true")
            self.end_headers()
            self.wfile.write(body)
            self.wfile.flush()
        except (BrokenPipeError, ConnectionAbortedError, ConnectionResetError, OSError):
            pass  # client disconnected or Windows socket error

    def _serve_frontend(self):
        """Serve the embedded frontend HTML directly from memory."""
        try:
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Content-Length", len(FRONTEND_HTML))
            self.send_header("Connection", "keep-alive")
            self.send_header("Cache-Control", "no-cache")
            self.end_headers()
            self.wfile.write(FRONTEND_HTML)
            self.wfile.flush()
        except (BrokenPipeError, ConnectionAbortedError, ConnectionResetError, OSError):
            pass

    def _body(self):
        # Cache result so body is only read once even across chained handlers
        if hasattr(self, '_body_cache'):
            return self._body_cache
        try:
            length = int(self.headers.get("Content-Length", 0) or 0)
            if length <= 0:
                self._body_cache = {}
                return {}
            raw = self.rfile.read(length)
            self._body_cache = json.loads(raw) if raw.strip() else {}
        except Exception:
            self._body_cache = {}
        return self._body_cache

    def do_OPTIONS(self):
        try:
            self.send_response(204)
            self.send_header("Access-Control-Allow-Origin", "*")
            self.send_header("Access-Control-Allow-Methods", "GET,POST,OPTIONS")
            self.send_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
            self.send_header("Access-Control-Allow-Credentials", "true")
            self.send_header("Access-Control-Max-Age", "86400")
            self.end_headers()
        except (BrokenPipeError, ConnectionAbortedError, ConnectionResetError):
            pass

    def do_GET(self):
        try:
            self._do_get_chain()
        except (BrokenPipeError, ConnectionAbortedError, ConnectionResetError):
            pass
        except Exception as e:
            try:
                self._send({"error": "Internal server error", "detail": str(e)}, 500)
            except Exception:
                pass

    def _do_get_chain(self):
        # Overridden by monkey-patch chain
        pass

    def _handle_get(self):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip("/")
        parts = [p for p in path.split("/") if p]

        # ── Serve frontend ──────────────────────────────────────────────────
        if path == "" or path == "/" or path == "/index.html":
            self._serve_frontend()
            return

        # ── API routes ───────────────────────────────────────────────────────
        if parts[0] != "api":
            # SPA fallback — serve index.html for any non-API route
            self._serve_frontend()
            return

        route = "/".join(parts[1:])

        if route == "health":
            self._send({"status": "ok" if _SERVER_READY else "warming_up",
                        "ready": _SERVER_READY,
                        "ts": datetime.now().isoformat()})

        elif route == "ping":
            self._send({"pong": True, "ts": datetime.now().isoformat()})

        elif route == "ready":
            import data_store as _ds
            _alerts = len(_ds.ALERTS)
            _done   = _ds.DATASET_INGESTION_DONE and _alerts > 0
            self._send({
                "ready":                  _done,
                "ingested_transactions":  len(_ds.INGESTED_TRANSACTIONS),
                "alerts_loaded":          _alerts,
                "cases_loaded":           len(_ds.CASES),
                "total_alerts":           _alerts,
            })

        elif route == "stats":
            self._send(get_system_stats())

        elif route == "alerts":
            status_filter = parse_qs(parsed.query).get("status", [None])[0]
            alerts = ALERTS if not status_filter else [a for a in ALERTS if a["status"] == status_filter]
            self._send({"alerts": alerts, "total": len(alerts)})

        elif len(parts) == 3 and parts[1] == "alerts":
            alert_id = parts[2]
            alert = next((a for a in ALERTS if a["id"] == alert_id), None)
            if alert:
                self._send(alert)
            else:
                self._send({"error": "Not found"}, 404)

        # ── Alert full transactions: GET /api/alerts/{id}/transactions ────────
        elif len(parts) == 4 and parts[1] == "alerts" and parts[3] == "transactions":
            alert_id = parts[2]
            try:
                alert = next((a for a in ALERTS if a["id"] == alert_id), None)
                if not alert:
                    self._send({"error": "Alert not found"}, 404); return
                entity = alert.get("entity", "")
                # Get all ingested transactions for this entity
                entity_txns = [t for t in INGESTED_TRANSACTIONS if t.get("entity_name") == entity]
                # If no ingested data, build synthetic records from alert's own transaction data
                if not entity_txns and alert.get("transactions"):
                    entity_txns = [{
                        "transaction_id": f"TXN-{i+1:05d}",
                        "entity_name": entity,
                        "amount": t.get("amount", 0),
                        "channel": alert.get("channel",""),
                        "timestamp": alert.get("timestamp",""),
                        "is_suspicious": 1,
                        "ml_score": alert.get("score", 0),
                        "typology_label": alert.get("typology",""),
                        "notes": t.get("desc",""),
                    } for i, t in enumerate(alert.get("transactions",[]))]
                flagged = [t for t in entity_txns if t.get("is_suspicious") == 1 or int(t.get("ml_score", 0)) >= 55]
                context = [t for t in entity_txns if not (t.get("is_suspicious") == 1 or int(t.get("ml_score", 0)) >= 55)]
                flagged.sort(key=lambda t: str(t.get("timestamp", "")), reverse=True)
                context.sort(key=lambda t: str(t.get("timestamp", "")), reverse=True)
                self._send({
                    "alert_id":      alert_id,
                    "entity":        entity,
                    "flagged":       flagged[:20],
                    "context":       context[:10],
                    "total_txns":    len(entity_txns),
                    "total_flagged": len(flagged),
                })
            except Exception as _e:
                self._send({"error": str(_e), "alert_id": alert_id,
                            "flagged": [], "context": [], "total_txns": 0, "total_flagged": 0})

        elif route == "cases":
            self._send({"cases": CASES, "total": len(CASES)})

        elif len(parts) == 3 and parts[1] == "cases":
            case_id = parts[2]
            case = next((c for c in CASES if c["id"] == case_id), None)
            if case:
                # Enrich with alerts
                case_alerts = [a for a in ALERTS if a.get("case_id") == case_id]
                self._send({**case, "alert_details": case_alerts})
            else:
                self._send({"error": "Not found"}, 404)

        elif route == "models/metrics":
            engine = get_engine()
            metrics = engine.get_metrics()
            importances = engine.get_feature_importances()
            self._send({
                "metrics": metrics,
                "trained_at": engine.trained_at,
                "feature_importances": importances,
            })

        elif route == "models/importances":
            engine = get_engine()
            imp = engine.get_feature_importances()
            from ml_engine import SHAP_LABELS
            result = [
                {"feature": k, "label": SHAP_LABELS.get(k, k), "importance": round(v, 4)}
                for k, v in sorted(imp.items(), key=lambda x: -x[1])
            ]
            self._send(result)

        elif route == "models/history":
            self._send(get_engine().get_training_history())

        elif route == "pipeline/stats":
            stats = get_system_stats()
            self._send({
                "txns_per_min": stats["txns_per_min"],
                "latency_ms": stats["pipeline_latency_ms"],
                "data_quality": stats["data_quality_score"],
                "features_count": 214,
                "feature_categories": {
                    "Velocity & Volume": 52,
                    "Network / Graph": 48,
                    "Behavioural Baseline": 44,
                    "Typology Indicators": 42,
                    "Entity Risk Context": 28,
                },
                "channels_live": CHANNELS,
            })

        elif route == "live/transaction":
            self._send(generate_live_transaction())

        elif route == "audit":
            limit = int(parse_qs(parsed.query).get("limit", [50])[0])
            self._send({"log": AUDIT_LOG[:limit]})

        elif route == "sar":
            self._send({"records": SAR_RECORDS, "total": len(SAR_RECORDS)})

        # ── Case history (permanent record of cleared cases) ─────────────────
        elif route == "case_history":
            self._send({"cases": CASE_HISTORY, "total": len(CASE_HISTORY)})

        # ── Supervisor queue: escalated cases ────────────────────────────────
        elif route == "supervisor/cases":
            escalated = [c for c in CASES if c.get("status") == "escalated"]
            self._send({"cases": escalated, "total": len(escalated)})

        else:
            self._send({"error": "Not found"}, 404)

    def do_POST(self):
        try:
            self._do_post_chain()
        except (BrokenPipeError, ConnectionAbortedError, ConnectionResetError):
            pass
        except Exception as e:
            try:
                self._send({"error": "Internal server error", "detail": str(e)}, 500)
            except Exception:
                pass

    def _do_post_chain(self):
        # This is overridden by the monkey-patch chain (_rules_post -> _auth_post -> _investigation_post)
        # Default implementation handles base routes only
        pass

    def _handle_post(self):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip("/")
        parts = [p for p in path.split("/") if p]

        if not parts or parts[0] != "api":
            self.send_response(404); self.end_headers(); return

        route = "/".join(parts[1:])
        body = self._body()

        # ── Score transaction ────────────────────────────────────────────────
        if route == "score":
            engine = get_engine()
            # Map API fields to engine feature names
            txn = {
                "amount":             float(body.get("amount", 50000)),
                "channel_idx":        CHANNELS.index(body.get("channel", "Wire Transfer")) if body.get("channel") in CHANNELS else 0,
                "tier_idx":           TIERS.index(body.get("tier", "Medium")) if body.get("tier") in TIERS else 1,
                "velocity_3d":        float(body.get("velocity_3d", 30)),
                "velocity_7d":        float(body.get("velocity_7d", 40)),
                "new_counterparty":   int(body.get("new_counterparty", 0)),
                "jurisdiction_idx":   JURISDICTIONS.index(body.get("jurisdiction", "Standard")) if body.get("jurisdiction") in JURISDICTIONS else 0,
                "round_dollar":       int(body.get("round_dollar", 0)),
                "hour_of_day":        int(body.get("hour_of_day", 12)),
                "counterparty_degree":int(body.get("counterparty_degree", 3)),
                "cross_border":       int(body.get("cross_border", 0)),
                "account_age_days":   int(body.get("account_age_days", 365)),
                "prior_sars":         int(body.get("prior_sars", 0)),
                "amount_vs_peer_pct": float(body.get("amount_vs_peer_pct", 100)),
                "multi_currency":     int(body.get("multi_currency", 0)),
            }
            result = engine.score_transaction(txn)
            _log({"user": "api", "action": "TRANSACTION_SCORED",
                  "target": "-", "detail": f"Score: {result['score']} / {result['priority']}"})
            self._send(result)

        # ── Alert actions ────────────────────────────────────────────────────
        elif len(parts) == 4 and parts[1] == "alerts" and parts[3] == "action":
            alert_id = parts[2]
            alert = next((a for a in ALERTS if a["id"] == alert_id), None)
            if not alert:
                self._send({"error": "Alert not found"}, 404); return
            action = body.get("action")
            notes  = body.get("notes", "")
            officer = body.get("officer", "Unknown")
            if action == "clear":
                alert["status"] = "cleared"
                alert["notes"] = notes
                _log({"user": officer, "action": "ALERT_CLEARED",
                      "target": alert_id, "detail": notes or "Cleared as false positive"})
                self._send({"ok": True, "alert": alert})
            elif action == "create_case":
                cid = f"CAS-{random.randint(500,999)}"
                alert["status"] = "review"
                alert["case_id"] = cid
                alert["officer"] = officer
                new_case = {
                    "id": cid, "entity": alert["entity"],
                    "alerts": [alert_id], "alert_count": 1,
                    "priority": alert["priority"], "status": "open",
                    "officer": officer,
                    "opened": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                    "sar_due": (datetime.now().replace(day=datetime.now().day)).strftime("%Y-%m-%d"),
                    "typology": alert["typology"],
                    "narrative": notes or f"Case opened from alert {alert_id}.",
                    "sar_status": "under_review",
                }
                CASES.insert(0, new_case)
                _log({"user": officer, "action": "CASE_CREATED",
                      "target": cid, "detail": f"From alert {alert_id}"})
                self._send({"ok": True, "case_id": cid, "case": new_case})
            elif action == "escalate":
                # Escalate to supervisor — record escalation metadata
                alert["priority"]         = "critical"
                alert["escalated"]        = True
                alert["escalated_by"]     = officer
                alert["escalated_at"]     = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                alert["escalated_to"]     = body.get("escalate_to", None)  # supervisor user_id or None = all
                alert["escalation_notes"] = notes
                alert["status"]           = "escalated"
                _log({"user": officer, "action": "ALERT_ESCALATED",
                      "target": alert_id,
                      "detail": f"Escalated by {officer} → supervisor review. {notes}"})
                self._send({"ok": True, "alert": alert})

            elif action == "assign":
                # Assign alert to a specific user (supervisor/admin only)
                ok_p, err_p = require_permission(token, "file_sar")
                if not ok_p:
                    self._send({"error":"Only supervisors and admins can assign alerts"}, 403); return
                assignee = body.get("assignee", "")
                alert["officer"]         = assignee
                alert["assigned_by"]     = officer
                alert["assigned_at"]     = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                alert["status"]          = alert.get("status","open") if alert.get("status") != "escalated" else "open"
                _log({"user": officer, "action": "ALERT_ASSIGNED",
                      "target": alert_id, "detail": f"Assigned to {assignee} by {officer}"})
                self._send({"ok": True, "alert": alert})
            elif action == "add_note":
                alert["notes"] = (alert.get("notes","") + "\n" + notes).strip()
                self._send({"ok": True, "alert": alert})
            else:
                self._send({"error": "Unknown action"}, 400)

        # ── Case update ──────────────────────────────────────────────────────
        elif len(parts) == 4 and parts[1] == "cases" and parts[3] == "update":
            case_id = parts[2]
            case = next((c for c in CASES if c["id"] == case_id), None)
            if not case:
                self._send({"error": "Case not found"}, 404); return
            for field in ["status", "narrative", "officer", "sar_status"]:
                if field in body:
                    case[field] = body[field]
            if body.get("sar_status") == "filed":
                officer_name = body.get("officer", case["officer"])
                fincen_ref2  = f"FIN-2024-{random.randint(100,999)}"
                filed_date2  = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                sar = {
                    "id": f"SAR-{random.randint(52,999):04d}",
                    "case_id": case_id,
                    "entity": case["entity"],
                    "amount": 0,
                    "typology": case["typology"],
                    "filed_date": filed_date2,
                    "officer": officer_name,
                    "status": "filed",
                    "fincen_ref": fincen_ref2,
                }
                SAR_RECORDS.insert(0, sar)
                # Mark all linked alerts as filed
                linked2 = [a for a in ALERTS if a.get("case_id") == case_id
                           or a["id"] in case.get("alerts", [])]
                for alert in linked2:
                    alert["status"]       = "filed"
                    alert["sar_status"]   = "filed"
                    alert["fincen_ref"]   = fincen_ref2
                    alert["filed_date"]   = filed_date2
                    alert["escalated_by"] = officer_name
                _log({"user": body.get("officer","system"), "action": "SAR_FILED",
                      "target": case_id, "detail": f"FinCEN ref: {sar['fincen_ref']}"})
            _log({"user": body.get("officer","system"), "action": "CASE_UPDATED",
                  "target": case_id, "detail": f"Status → {body.get('status','')}"})
            self._send({"ok": True, "case": case})

        # ── Case: escalate to supervisor queue ───────────────────────────────
        elif len(parts) == 4 and parts[1] == "cases" and parts[3] == "escalate":
            case_id = parts[2]
            case = next((c for c in CASES if c["id"] == case_id), None)
            if not case:
                self._send({"error": "Case not found"}, 404); return
            officer  = body.get("officer", case.get("officer","Unknown"))
            sup_name = body.get("supervisor", "")
            notes    = body.get("notes", "")
            # Save narrative if provided
            if body.get("narrative"):
                case["narrative"] = body["narrative"]
            case["status"]       = "escalated"
            case["sar_status"]   = "escalated"
            case["escalated_by"] = officer
            case["escalated_at"] = datetime.now().isoformat()
            case["supervisor"]   = sup_name
            ESCALATED_CASES[case_id] = {
                "case_id":      case_id,
                "escalated_by": officer,
                "escalated_at": case["escalated_at"],
                "supervisor":   sup_name,
                "notes":        notes,
            }
            _log({"user": officer, "action": "CASE_ESCALATED",
                  "target": case_id, "detail": f"Escalated to supervisor. {notes}"})
            self._send({"ok": True, "case": case})

        # ── Case: clear case → move to history ──────────────────────────────
        elif len(parts) == 4 and parts[1] == "cases" and parts[3] == "clear":
            case_id = parts[2]
            case = next((c for c in CASES if c["id"] == case_id), None)
            if not case:
                self._send({"error": "Case not found"}, 404); return
            officer = body.get("officer", case.get("officer","Unknown"))
            reason  = body.get("reason", "No suspicious activity found")
            now = datetime.now().isoformat()
            # Update case IN PLACE — stays visible in Case Management with cleared badge
            case["status"]       = "cleared"
            case["cleared_at"]   = now
            case["cleared_by"]   = officer
            case["clear_reason"] = reason
            # Also write full snapshot to Case History (separate permanent store)
            cleared_entry = dict(case)
            CASE_HISTORY.insert(0, cleared_entry)
            _save_case_history(CASE_HISTORY)
            ESCALATED_CASES.pop(case_id, None)
            _log({"user": officer, "action": "CASE_CLEARED",
                  "target": case_id, "detail": f"Cleared: {reason}"})
            self._send({"ok": True, "cleared": case_id, "case": case})

        # ── Case: supervisor action (approve SAR / return / clear) ───────────
        elif len(parts) == 4 and parts[1] == "cases" and parts[3] == "supervisor_action":
            case_id = parts[2]
            case = next((c for c in CASES if c["id"] == case_id), None)
            if not case:
                self._send({"error": "Case not found"}, 404); return
            action  = body.get("action")   # "file_sar" | "return" | "clear"
            officer = body.get("officer", "Supervisor")
            notes   = body.get("notes", "")
            if action == "return":
                # Return to original officer
                case["status"]     = "open"
                case["sar_status"] = "pending"
                case["supervisor_note"] = notes
                ESCALATED_CASES.pop(case_id, None)
                _log({"user": officer, "action": "CASE_RETURNED",
                      "target": case_id, "detail": f"Returned to {case.get('officer','')}. {notes}"})
                self._send({"ok": True, "action": "returned", "case": case})
            elif action == "clear":
                # Supervisor clears without SAR
                now = datetime.now().isoformat()
                reason_text = notes or "Cleared by supervisor — no SAR required"
                # Update case IN PLACE — stays in Case Management with cleared badge
                case["status"]       = "cleared"
                case["cleared_at"]   = now
                case["cleared_by"]   = officer
                case["clear_reason"] = reason_text
                # Write snapshot to Case History (separate permanent store)
                cleared_entry = dict(case)
                CASE_HISTORY.insert(0, cleared_entry)
                _save_case_history(CASE_HISTORY)
                ESCALATED_CASES.pop(case_id, None)
                _log({"user": officer, "action": "CASE_CLEARED_BY_SUPERVISOR",
                      "target": case_id, "detail": reason_text})
                self._send({"ok": True, "action": "cleared", "case_id": case_id, "case": case})
            elif action == "file_sar":
                case["status"]     = "filed"
                case["sar_status"] = "filed"
                fincen_ref = f"FIN-2024-{random.randint(100,999)}"
                filed_ts   = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                sar = {
                    "id": f"SAR-{random.randint(52,999):04d}",
                    "case_id": case_id,
                    "entity": case["entity"],
                    "amount": case.get("amount", 0),
                    "typology": case["typology"],
                    "filed_date": filed_ts,
                    "officer": officer,
                    "status": "filed",
                    "fincen_ref": fincen_ref,
                }
                SAR_RECORDS.insert(0, sar)
                # Mark ALL linked alerts as filed
                linked_alerts = [a for a in ALERTS if
                                 a.get("case_id") == case_id or
                                 a["id"] in case.get("alerts", [])]
                for _a in linked_alerts:
                    _a["status"]       = "filed"
                    _a["sar_status"]   = "filed"
                    _a["fincen_ref"]   = fincen_ref
                    _a["filed_date"]   = filed_ts
                    _a["escalated_by"] = officer
                # Manual SARs have no linked alerts — create a synthetic alert record
                # so it appears in the Filed Alerts box exactly like system-generated cases
                if case.get("manual_sar") and not linked_alerts:
                    synthetic_alert = {
                        "id":           f"ALT-M{random.randint(1000,9999)}",
                        "entity":       case["entity"],
                        "amount":       float(case.get("amount", 0)),
                        "score":        case.get("score", 85),
                        "priority":     case.get("priority", "high"),
                        "typology":     case["typology"],
                        "channel":      case.get("channels", "Manual submission"),
                        "timestamp":    filed_ts,
                        "status":       "filed",
                        "sar_status":   "filed",
                        "officer":      case.get("officer", officer),
                        "case_id":      case_id,
                        "fincen_ref":   fincen_ref,
                        "filed_date":   filed_ts,
                        "escalated_by": officer,
                        "manual_sar":   True,
                        "notes":        f"Manual SAR — submitted via SAR Editor. FinCEN ref: {fincen_ref}",
                    }
                    ALERTS.insert(0, synthetic_alert)
                    linked_alerts = [synthetic_alert]
                ESCALATED_CASES.pop(case_id, None)
                _log({"user": officer, "action": "SAR_FILED_BY_SUPERVISOR",
                      "target": case_id,
                      "detail": f"FinCEN ref: {fincen_ref}. {len(linked_alerts)} alert(s) filed. Manual SAR: {case.get('manual_sar', False)}"})
                self._send({"ok": True, "action": "filed", "fincen_ref": fincen_ref,
                            "alerts_filed": len(linked_alerts), "case": case})
            else:
                self._send({"error": "Unknown action"}, 400)

        # ── Case: save narrative (permanent edit) ────────────────────────────
        elif len(parts) == 4 and parts[1] == "cases" and parts[3] == "save_narrative":
            case_id = parts[2]
            case = next((c for c in CASES if c["id"] == case_id), None)
            if not case:
                self._send({"error": "Case not found"}, 404); return
            case["narrative"] = body.get("narrative", case.get("narrative",""))
            _log({"user": body.get("officer","system"), "action": "NARRATIVE_EDITED",
                  "target": case_id, "detail": "Investigation narrative updated"})
            self._send({"ok": True, "case_id": case_id})

        # ── Case: set review / open status toggle ─────────────────────────────
        # ── Manual SAR draft → create case → supervisor queue ─────────────────
        elif route == "sar/manual_submit":
            officer     = body.get("officer", "Officer")
            entity      = body.get("entity_name", "Unknown Entity")
            entity_type = body.get("entity_type", "Business")
            typo        = body.get("typology", "Suspicious Activity")
            amount      = body.get("amount", 0)
            date_range  = body.get("date_range", "")
            channels    = body.get("channels", "")
            narrative   = body.get("narrative", "")
            address     = body.get("address", "")
            account_no  = body.get("account_no", "")
            ein_dob     = body.get("ein_dob", "")
            now = datetime.now().isoformat()
            case_id = f"CAS-M{random.randint(1000,9999)}"
            new_case = {
                "id":           case_id,
                "entity":       entity,
                "entity_type":  entity_type,
                "alerts":       [],
                "alert_count":  0,
                "priority":     "high",
                "status":       "escalated",
                "officer":      officer,
                "opened":       now,
                "sar_due":      (datetime.now() + __import__("datetime").timedelta(days=29)).strftime("%Y-%m-%d %H:%M:%S"),
                "typology":     typo,
                "narrative":    narrative,
                "sar_status":   "escalated",
                "escalated_by": officer,
                "escalated_at": now,
                "supervisor":   "",
                "manual_sar":   True,
                "amount":       amount,
                "date_range":   date_range,
                "channels":     channels,
                "address":      address,
                "account_no":   account_no,
                "ein_dob":      ein_dob,
                "source":       "manual_sar_editor",
            }
            CASES.insert(0, new_case)
            ESCALATED_CASES[case_id] = {
                "case_id": case_id, "escalated_by": officer,
                "escalated_at": now, "supervisor": "",
                "notes": f"Manual SAR. Typology: {typo}.", "manual_sar": True,
            }
            _log({"user": officer, "action": "MANUAL_SAR_SUBMITTED",
                  "target": case_id, "detail": f"Manual SAR for {entity} ({typo})"})
            self._send({"ok": True, "case_id": case_id})

        elif len(parts) == 4 and parts[1] == "cases" and parts[3] == "set_review":
            case_id = parts[2]
            case = next((c for c in CASES if c["id"] == case_id), None)
            if not case:
                self._send({"error": "Case not found"}, 404); return
            officer    = body.get("officer", case.get("officer","Unknown"))
            new_status = body.get("status", "review")
            case["status"] = new_status
            _log({"user": officer, "action": "CASE_STATUS_CHANGED",
                  "target": case_id, "detail": f"Status set to {new_status}"})
            self._send({"ok": True, "case": case})

        # ── Model retrain ────────────────────────────────────────────────────
        elif route == "models/retrain":
            def do_retrain():
                engine = get_engine()
                engine.train()
                _log({"user": "system", "action": "MODEL_RETRAINED",
                      "target": "ensemble", "detail": "Manual retrain triggered"})
            t = threading.Thread(target=do_retrain)
            t.start()
            self._send({"ok": True, "message": "Retraining started in background"})

        else:
            self._send({"error": "Not found"}, 404)


# Global readiness flag — checked by /api/health endpoint
_SERVER_READY = False

def run(port=None):
    global _SERVER_READY
    port = port or int(os.environ.get('PORT', PORT))
    print(f"\n{'='*55}", flush=True)
    print(f"  AML-TMS Platform", flush=True)
    print(f"  Port: {port}", flush=True)
    print(f"{'='*55}", flush=True)

    # ── Step 1: Bind port FIRST — Render/Railway need this within seconds ─────
    server = ThreadedHTTPServer(("0.0.0.0", port), AMLHandler)
    server_thread = threading.Thread(target=server.serve_forever, daemon=True)
    server_thread.start()
    print(f"  Port {port} bound", flush=True)

    # ── Step 2: Train ML engine (~3s) ─────────────────────────────────────────
    print("  Training ML models...", flush=True)
    get_engine()
    print("  ML engine ready", flush=True)

    # ── Step 3: Ingest dataset (<1s batch) ────────────────────────────────────
    try:
        import data_store as _ds
        if not _ds.DATASET_INGESTION_DONE:
            _ds._ingest_dataset()
            _ds.DATASET_INGESTION_DONE = True
        print(f"  {len(_ds.ALERTS)} alerts loaded", flush=True)
    except Exception as _e:
        print(f"  Ingestion warning: {_e}", flush=True)

    # ── Step 4: Mark ready — /api/health now returns status=ok ───────────────
    _SERVER_READY = True
    print(f"  READY — {len(FRONTEND_HTML)} bytes frontend", flush=True)
    print(f"{'='*55}\n", flush=True)

    try:
        server_thread.join()
    except KeyboardInterrupt:
        server.shutdown()
        print("\n  Stopped.")

if __name__ == "__main__":
    port = int(os.environ.get('PORT', PORT))
    run(port)

# ── Additional endpoints (appended) ──────────────────────────────────────────
# Monkey-patch the GET handler to add new routes

_original_get = AMLHandler._handle_get  # base handler serves frontend + core API

def _extended_get(self):
    parsed = urlparse(self.path)
    path = parsed.path.rstrip("/")
    parts = [p for p in path.split("/") if p]

    if not parts or parts[0] != "api":
        _original_get(self)
        return

    route = "/".join(parts[1:])

    if route == "features/summary":
        import sys, os
        sys.path.insert(0, os.path.dirname(__file__))
        from feature_engineering import get_feature_summary
        self._send(get_feature_summary())

    elif route == "monitor/report":
        from model_monitor import generate_monitoring_report
        self._send(generate_monitoring_report())

    elif len(parts) == 4 and parts[1] == "sar" and parts[2] == "generate":
        # /api/sar/generate/{case_id}
        case_id = parts[3] if len(parts) > 3 else None
        if case_id:
            case = next((c for c in CASES if c["id"] == case_id), None)
            if case:
                from sar_engine import generate_sar, get_sar_checklist
                case_alerts = [a for a in ALERTS if a.get("case_id") == case_id]
                sar = generate_sar(case, case_alerts, case.get("officer", "AML Officer"))
                checklist = get_sar_checklist(sar)
                self._send({"sar": sar, "checklist": checklist})
                return
        self._send({"error": "Case not found"}, 404)

    else:
        _original_get(self)

AMLHandler._do_get_chain = _extended_get

# ── Investigation, Sanctions & Notification endpoints ─────────────────────────
_original_get2  = AMLHandler._handle_get  # base handler
_original_post2 = AMLHandler._handle_post  # base handler

def _investigation_get(self):
    parsed = urlparse(self.path)
    path   = parsed.path.rstrip("/")
    parts  = [p for p in path.split("/") if p]
    if not parts or parts[0] != "api":
        _original_get2(self)
        return
    route = "/".join(parts[1:])

    # ── Sanctions ──────────────────────────────────────────────────────────
    if route == "sanctions/stats":
        self._send(get_sdn_stats())

    elif route.startswith("sanctions/screen/"):
        name    = "/".join(parts[3:]).replace("%20"," ").replace("+"," ")
        from urllib.parse import parse_qs
        qs      = parse_qs(parsed.query)
        country = qs.get("country",[""])[0]
        result  = screen_entity(name, country or None)
        # Auto-notify if confirmed hit
        if result["status"] == "HIT" and result["matches"]:
            trigger_sanctions_hit_notification(name, result["matches"][0])
        self._send(result)

    # ── SAR Drafts ─────────────────────────────────────────────────────────
    elif route == "sar/drafts":
        self._send({"drafts": list_sar_drafts(), "total": len(list_sar_drafts())})

    elif len(parts) == 4 and parts[1]=="sar" and parts[2]=="draft":
        draft = get_sar_draft(parts[3])
        self._send(draft if draft else {"error":"Draft not found"}, 200 if draft else 404)

    elif len(parts) == 5 and parts[1]=="sar" and parts[2]=="draft" and parts[4]=="revision":
        # /api/sar/draft/{case_id}/revision?id=xxx
        from urllib.parse import parse_qs as pqs
        rev_id = pqs(parsed.query).get("id",[""])[0]
        rev    = get_sar_revision(parts[3], rev_id)
        self._send(rev if rev else {"error":"Revision not found"}, 200 if rev else 404)

    # ── Documents ──────────────────────────────────────────────────────────
    elif len(parts) == 4 and parts[1]=="cases" and parts[3]=="documents":
        self._send({"documents": get_documents(parts[2]), "case_id": parts[2]})

    elif len(parts) == 4 and parts[1]=="documents" and parts[3]=="download":
        data, meta = get_document_data(parts[2])
        if data:
            self.send_response(200)
            self.send_header("Content-Type", meta.get("content_type","application/octet-stream"))
            self.send_header("Content-Disposition",
                             f'attachment; filename="{meta.get("filename","file")}"')
            self.send_header("Content-Length", len(data))
            self.send_header("Access-Control-Allow-Origin","*")
            self.send_header("Access-Control-Allow-Headers","Content-Type, Authorization")
            self.end_headers()
            self.wfile.write(data)
        else:
            self._send({"error":"Document not found"},404)

    # ── Entity Graph ───────────────────────────────────────────────────────
    elif len(parts) == 4 and parts[1]=="cases" and parts[3]=="graph":
        case_id     = parts[2]
        case_alerts = [a for a in ALERTS if a.get("case_id")==case_id]
        graph       = build_entity_graph(case_id, case_alerts, CASES)
        self._send(graph)

    # ── Notifications ──────────────────────────────────────────────────────
    elif route == "notifications":
        from urllib.parse import parse_qs as pqs
        qs     = pqs(parsed.query)
        limit  = int(qs.get("limit",["50"])[0])
        etype  = qs.get("type",[""])[0] or None
        self._send({"notifications": get_notifications(limit, etype),
                    "stats": get_notification_stats()})

    elif route == "notifications/stats":
        self._send(get_notification_stats())

    else:
        _original_get2(self)

def _investigation_post(self):
    try:
        _investigation_post_inner(self)
    except (BrokenPipeError, ConnectionAbortedError, ConnectionResetError):
        pass
    except Exception as e:
        try:
            self._send({"error": str(e)}, 500)
        except Exception:
            pass

def _investigation_post_inner(self):
    parsed = urlparse(self.path)
    path   = parsed.path.rstrip("/")
    parts  = [p for p in path.split("/") if p]
    if not parts or parts[0] != "api":
        _original_post2(self)
        return
    route = "/".join(parts[1:])
    body  = self._body()

    # ── Sanctions batch screen ──────────────────────────────────────────────
    if route == "sanctions/screen":
        name    = body.get("name","")
        country = body.get("country","")
        result  = screen_entity_with_ownership(name, country=country or None, max_depth=4)
        if result["status"] == "HIT" and result["matches"]:
            trigger_sanctions_hit_notification(name, result["matches"][0])
        _log({"user": body.get("officer","api"), "action":"SANCTIONS_SCREEN",
              "target": name, "detail": f"Result: {result['status']}"})
        self._send(result)

    elif route == "sanctions/batch":
        entities = body.get("entities",[])
        results  = batch_screen(entities)
        hits     = [r for r in results if r["status"]=="HIT"]
        self._send({"results": results, "hits": len(hits), "total": len(results)})

    elif route == "sanctions/batch-upload":
        # Multipart file upload — parse manually
        import base64 as _b64
        try:
            file_b64  = body.get("file_data", "")
            filename  = body.get("filename", "upload.txt")
            if not file_b64:
                self._send({"error": "No file data received"}, 400)
            else:
                file_bytes = _b64.b64decode(file_b64)
                names      = extract_names(file_bytes, filename)
                if not names:
                    self._send({"error": "No names found in the uploaded file. "
                                         "Ensure the file contains one name per line/cell."}, 400)
                else:
                    # Screen all names
                    results = []
                    for name in names:
                        r = screen_entity(name.strip(), None)
                        results.append(r)
                    # Generate Excel report
                    report_bytes = generate_batch_report(results, filename)
                    report_b64   = _b64.b64encode(report_bytes).decode("ascii")
                    # Stats
                    confirmed = sum(1 for r in results if r["status"] == "HIT")
                    potential = sum(1 for r in results if r["status"] == "POTENTIAL_MATCH")
                    clear     = sum(1 for r in results if r["status"] == "CLEAR")
                    _log({"user": body.get("officer","api"), "action": "BATCH_SANCTIONS_SCREEN",
                          "target": filename,
                          "detail": f"{len(names)} names: {confirmed} hits, {potential} potential"})
                    self._send({
                        "ok":           True,
                        "total":        len(names),
                        "confirmed":    confirmed,
                        "potential":    potential,
                        "clear":        clear,
                        "report_b64":   report_b64,
                        "report_name":  f"SDN_Batch_Screen_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx",
                    })
        except ValueError as ve:
            self._send({"error": str(ve)}, 400)
        except Exception as e:
            self._send({"error": f"Batch screening failed: {str(e)}"}, 500)

    # ── SAR Draft save ─────────────────────────────────────────────────────
    elif route == "sar/draft/save":
        r = save_sar_draft(
            case_id  = body.get("case_id",""),
            content  = body.get("content",""),
            officer  = body.get("officer","Unknown"),
            title    = body.get("title"),
            status   = body.get("status","draft"),
        )
        _log({"user": body.get("officer","api"), "action":"SAR_DRAFT_SAVED",
              "target": body.get("case_id",""), "detail": f"Rev {r.get('revision_id')} — {r.get('word_count',0)} words"})
        self._send(r)

    # ── Document upload ────────────────────────────────────────────────────
    # ── Case-specific document upload: POST /api/cases/{id}/documents/upload ──
    elif len(parts) == 5 and parts[1] == "cases" and parts[3] == "documents" and parts[4] == "upload":
        case_id = parts[2]
        r = upload_document(
            case_id      = case_id,
            filename     = body.get("filename", "file"),
            content_type = body.get("content_type", "application/octet-stream"),
            data_b64     = body.get("data", ""),
            uploaded_by  = body.get("officer", "Unknown"),
            description  = body.get("note", ""),
        )
        if r.get("ok"):
            _log({"user": body.get("officer","api"), "action": "DOCUMENT_UPLOADED",
                  "target": case_id,
                  "detail": f"{body.get('filename','')} uploaded to {case_id}"})
        self._send(r)

    elif route == "documents/upload":
        r = upload_document(
            case_id      = body.get("case_id",""),
            filename     = body.get("filename","file"),
            content_type = body.get("content_type","application/octet-stream"),
            data_b64     = body.get("data",""),
            uploaded_by  = body.get("officer","Unknown"),
            description  = body.get("description",""),
        )
        if r.get("ok"):
            _log({"user": body.get("officer","api"), "action":"DOCUMENT_UPLOADED",
                  "target": body.get("case_id",""),
                  "detail": f"{body.get('filename','')} ({r.get('doc',{}).get('size_kb',0)}KB)"})
        self._send(r)

    elif len(parts)==4 and parts[1]=="documents" and parts[3]=="delete":
        r = delete_document(parts[2], body.get("doc_id",""), body.get("officer",""))
        _log({"user": body.get("officer","api"), "action":"DOCUMENT_DELETED",
              "target": parts[2], "detail": body.get("doc_id","")})
        self._send(r)

    # ── Notifications ──────────────────────────────────────────────────────
    elif route == "notifications/send":
        r = send_notification(
            event_type = body.get("event_type","MANUAL"),
            subject    = body.get("subject",""),
            body       = body.get("body",""),
            data       = body.get("data",{}),
            recipients = body.get("recipients"),
        )
        self._send(r)

    elif route == "notifications/configure":
        r = configure_email(body)
        self._send(r)

    elif route == "notifications/test":
        r = send_notification(
            event_type = "TEST",
            subject    = "AML-TMS Test Notification",
            body       = "This is a test notification from AML-TMS. Your email configuration is working correctly.",
            data       = {"Sent at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                          "Platform": "AML-TMS v2.4"},
            recipients = body.get("recipients", EMAIL_CONFIG.get("recipients",[])),
        )
        self._send(r)

    # ── Trigger alert notification ─────────────────────────────────────────
    elif route == "alerts/notify":
        alert_id = body.get("alert_id","")
        alert    = next((a for a in ALERTS if a["id"]==alert_id), None)
        if alert:
            r = trigger_alert_notification(alert)
            self._send(r)
        else:
            self._send({"error":"Alert not found"},404)

    else:
        _original_post2(self)

AMLHandler._do_get_chain  = _investigation_get
AMLHandler._do_post_chain = _investigation_post

# ── Auth, Analytics & Reporting endpoints ─────────────────────────────────────
_prev_get3  = AMLHandler._do_get_chain
_prev_post3 = AMLHandler._do_post_chain

def _get_token(self):
    """Extract bearer token from Authorization header or cookie."""
    auth = self.headers.get("Authorization","")
    if auth.startswith("Bearer "):
        return auth[7:]
    # Also accept X-Auth-Token header
    return self.headers.get("X-Auth-Token","")

def _auth_get(self):
    parsed = urlparse(self.path)
    path   = parsed.path.rstrip("/")
    parts  = [p for p in path.split("/") if p]
    if not parts or parts[0] != "api":
        _prev_get3(self); return
    route = "/".join(parts[1:])
    token = _get_token(self)

    # ── Auth ───────────────────────────────────────────────────────────────
    if route == "auth/me":
        # No-auth mode: always return admin user
        from auth import PERMISSIONS
        self._send({
            "user": {
                "user_id": "usr_admin",
                "name": "Ransford Adjapong",
                "email": "r.adjapong@fncb.com",
                "role": "admin",
                "department": "AML Compliance",
                "active": True,
                "avatar": "R",
                "color": "#7832B4",
            },
            "permissions": sorted(PERMISSIONS.get("admin", []))
        })

    elif route == "auth/sessions":
        ok, err = True, {}  # no-auth:  "manage_users")
        # no-auth: permission check skipped
        self._send({"sessions": get_active_sessions()})

    # ── User management ────────────────────────────────────────────────────
    elif route == "users":
        # Admins see all users + role management
        # Supervisors see all users (needed for alert assignment)
        # Analysts see basic list (needed to know who to escalate to)
        user = get_current_user(token)
        if not user:
            # No-auth mode: default to admin user
            from auth import USERS
            user = USERS.get("usr_admin", list(USERS.values())[0])
        role = user.get("role","readonly")
        if role in ("admin","supervisor","analyst"):
            # Supervisors/analysts get user list but not sensitive admin data
            all_users = list_users()
            if role == "analyst":
                # Analysts only see supervisors/admins to know who to escalate to
                all_users = [u for u in all_users if u["role"] in ("supervisor","admin")]
            self._send({"users": all_users, "roles": list(get_all_roles().keys()),
                        "can_manage": role == "admin"})
        else:
            self._send({"error":"Access denied"}, 403)

    elif route == "supervisor/queue":
        # Supervisor's dedicated escalation queue
        user = get_current_user(token)
        if not user:
            # No-auth mode: default to admin user
            from auth import USERS
            user = USERS.get("usr_admin", list(USERS.values())[0])
        role = user.get("role","readonly")
        if role not in ("supervisor","admin"):
            self._send({"error":"Supervisor access required"}, 403); return
        uid  = user.get("user_id","")
        name = user.get("name","")
        # Get alerts escalated to this supervisor (or unassigned escalations)
        escalated = [a for a in ALERTS if
                     a.get("escalated") and
                     a.get("status") == "escalated" and
                     (a.get("escalated_to") == uid or
                      a.get("escalated_to") is None or
                      a.get("officer") == name)]
        # Also alerts directly assigned to this supervisor
        assigned  = [a for a in ALERTS if
                     a.get("officer") == name and
                     a.get("status") not in ("cleared","filed") and
                     not a.get("escalated")]
        # All filed alerts (SAR submitted) — shown in Filed Alerts box
        filed = [a for a in ALERTS if a.get("status") == "filed" or a.get("sar_status") == "filed"]
        self._send({
            "escalated_alerts": escalated,
            "assigned_alerts":  assigned,
            "filed_alerts":     filed,
            "total_pending":    len(escalated) + len(assigned),
        })

    elif route == "users/audit":
        ok, err = True, {}  # no-auth:  "view_all_audit")
        # no-auth: permission check skipped
        from urllib.parse import parse_qs as pqs
        uid = pqs(parsed.query).get("user_id",[""])[0] or None
        self._send({"audit": get_user_audit(uid, 200)})

    elif route == "roles":
        self._send(get_all_roles())

    # ── Analytics ──────────────────────────────────────────────────────────
    elif route == "analytics/executive":
        from urllib.parse import parse_qs as pqs
        period = pqs(parsed.query).get("period",["quarterly"])[0]
        self._send(get_executive_dashboard(period))

    elif route == "analytics/trends":
        from urllib.parse import parse_qs as pqs
        months = int(pqs(parsed.query).get("months",["12"])[0])
        self._send(get_trend_analysis(months))

    elif route == "analytics/geographic":
        self._send(get_geographic_risk())

    elif route == "analytics/confusion_matrix":
        from data_store import INGESTED_TRANSACTIONS
        txns = INGESTED_TRANSACTIONS
        if not txns:
            self._send({"error": "No data"}); return
        labels_d = [t.get("is_suspicious", 0) for t in txns]
        scores_d = [t.get("ml_score", 0) for t in txns]
        thresholds_d = [40, 50, 55, 60, 65, 70, 75, 80, 85, 90]
        cm_results = []
        for thresh in thresholds_d:
            tp = sum(1 for s,l in zip(scores_d,labels_d) if s>=thresh and l==1)
            fp = sum(1 for s,l in zip(scores_d,labels_d) if s>=thresh and l==0)
            tn = sum(1 for s,l in zip(scores_d,labels_d) if s< thresh and l==0)
            fn = sum(1 for s,l in zip(scores_d,labels_d) if s< thresh and l==1)
            prec = tp/(tp+fp) if (tp+fp)>0 else 0
            rec  = tp/(tp+fn) if (tp+fn)>0 else 0
            f1   = 2*prec*rec/(prec+rec) if (prec+rec)>0 else 0
            fpr  = fp/(fp+tn) if (fp+tn)>0 else 0
            acc  = (tp+tn)/len(labels_d) if labels_d else 0
            spec = tn/(tn+fp) if (tn+fp)>0 else 0
            cm_results.append({
                "threshold": thresh, "tp": tp, "fp": fp, "tn": tn, "fn": fn,
                "precision": round(prec,4), "recall": round(rec,4), "f1": round(f1,4),
                "fpr": round(fpr,4), "accuracy": round(acc,4), "specificity": round(spec,4),
                "total_flagged": tp+fp, "flag_rate": round((tp+fp)/len(labels_d)*100, 2),
                "priority": "critical" if thresh>=90 else "high" if thresh>=70 else "medium" if thresh>=55 else "monitor",
            })
        roc = [(0,0)]+[(r["fpr"],r["recall"]) for r in cm_results]+[(1,1)]
        roc.sort()
        auc_val = sum((roc[i+1][0]-roc[i][0])*(roc[i+1][1]+roc[i][1])/2 for i in range(len(roc)-1))
        susp_s  = [t.get("ml_score",0) for t in txns if t.get("is_suspicious")==1]
        clean_s = [t.get("ml_score",0) for t in txns if t.get("is_suspicious")==0]
        buckets = [0]*10
        for s in scores_d: buckets[min(int(s//10),9)] += 1
        self._send({
            "thresholds": cm_results, "auc": round(auc_val,4),
            "total": len(labels_d), "positives": sum(labels_d),
            "negatives": len(labels_d)-sum(labels_d),
            "susp_mean_score":  round(sum(susp_s)/len(susp_s),1) if susp_s else 0,
            "clean_mean_score": round(sum(clean_s)/len(clean_s),1) if clean_s else 0,
            "score_distribution": [{"range": f"{i*10}-{i*10+9}", "count": buckets[i]} for i in range(10)],
        })

    elif route == "analytics/report":
        from urllib.parse import parse_qs as pqs
        rtype  = pqs(parsed.query).get("type",["quarterly"])[0]
        period = pqs(parsed.query).get("period",[""])[0] or None
        self._send(get_pdf_report_data(rtype, period))

    else:
        _prev_get3(self)

def _auth_post(self):
    try:
        _auth_post_inner(self)
    except (BrokenPipeError, ConnectionAbortedError, ConnectionResetError):
        pass
    except Exception as e:
        try:
            self._send({"error": str(e)}, 500)
        except Exception:
            pass

def _auth_post_inner(self):
    parsed = urlparse(self.path)
    path   = parsed.path.rstrip("/")
    parts  = [p for p in path.split("/") if p]
    if not parts or parts[0] != "api":
        _prev_post3(self); return
    route = "/".join(parts[1:])
    body  = self._body()
    token = _get_token(self)

    # ── Authentication ─────────────────────────────────────────────────────
    if route == "auth/login":
        # No-auth mode: always return success with admin permissions
        from auth import PERMISSIONS
        self._send({
            "ok": True,
            "token": "demo-token-no-auth",
            "role": "admin",
            "permissions": sorted(PERMISSIONS.get("admin", [])),
            "user": {
                "user_id": "usr_admin",
                "name": "Ransford Adjapong",
                "email": body.get("email","r.adjapong@fncb.com"),
                "role": "admin",
                "department": "AML Compliance",
                "active": True,
                "avatar": "R",
                "color": "#7832B4",
            }
        })

    elif route == "auth/logout":
        self._send(logout(token))

    elif route == "auth/2fa/verify":
        r = verify_2fa(
            temp_token = body.get("temp_token",""),
            code       = str(body.get("code","")),
            ip         = self.client_address[0],
        )
        self._send(r, 200 if r.get("ok") else 401)

    elif route == "auth/2fa/toggle":
        ok, err = True, {}  # no-auth:  "view_dashboard")  # any logged-in user
        # no-auth: permission check skipped
        user = get_current_user(token)
        r = toggle_2fa(user["user_id"], body.get("enabled", True))
        self._send(r)

    elif route == "auth/change_password":
        user = get_current_user(token)
        if not user:
            from auth import USERS
            user = USERS.get("usr_admin", list(USERS.values())[0])
        r = update_user(user["user_id"],
                        {"password": body.get("new_password","")},
                        user["user_id"])
        self._send(r)

    # ── User management ────────────────────────────────────────────────────
    elif route == "users/create":
        ok, err = True, {}  # no-auth:  "manage_users")
        # no-auth: permission check skipped
        admin = get_current_user(token)
        r = create_user(
            name       = body.get("name",""),
            email      = body.get("email",""),
            password   = body.get("password","TempPass@2024"),
            role       = body.get("role","analyst"),
            department = body.get("department","AML Compliance"),
            created_by = admin["user_id"],
        )
        _log({"user": admin["name"], "action":"USER_CREATED",
              "target": body.get("email",""), "detail": f"Role: {body.get('role','analyst')}"})
        self._send(r)

    elif route == "users/update":
        ok, err = True, {}  # no-auth:  "manage_users")
        # no-auth: permission check skipped
        admin = get_current_user(token)
        r = update_user(body.get("user_id",""), body.get("updates",{}),
                        admin["user_id"])
        self._send(r)

    elif route == "users/unlock":
        ok, err = True, {}  # no-auth:  "manage_users")
        # no-auth: permission check skipped
        admin = get_current_user(token)
        r = unlock_user(body.get("user_id",""), admin["user_id"])
        self._send(r)

    # ── Log user action from frontend ─────────────────────────────────────
    elif route == "auth/log_action":
        user = get_current_user(token)
        if user:
            log_user_action(user["user_id"],
                            body.get("action","PAGE_VIEW"),
                            body.get("target",""),
                            body.get("detail",""))
        self._send({"ok": True})

    else:
        _prev_post3(self)

AMLHandler._do_get_chain  = _auth_get
AMLHandler._do_post_chain = _auth_post

# Attach _get_token as a method
AMLHandler._get_token = _get_token

# ── Static Rules endpoints ─────────────────────────────────────────────────────
_prev_get_rules  = AMLHandler._do_get_chain
_prev_post_rules = AMLHandler._do_post_chain

def _rules_get(self):
    parsed = urlparse(self.path)
    path   = parsed.path.rstrip("/")
    parts  = [p for p in path.split("/") if p]
    if not parts or parts[0] != "api":
        _prev_get_rules(self); return
    route = "/".join(parts[1:])

    if route == "rules":
        from static_rules import get_rules_summary
        self._send({"rules": get_rules_summary(), "total": 15})

    elif route == "rules/comparison":
        from static_rules import compare_ml_vs_rules
        from data_store import INGESTED_TRANSACTIONS, RAW_TRANSACTIONS
        txns = INGESTED_TRANSACTIONS if INGESTED_TRANSACTIONS else RAW_TRANSACTIONS[:200]
        self._send(compare_ml_vs_rules(txns))

    else:
        _prev_get_rules(self)

def _rules_post(self):
    parsed = urlparse(self.path)
    path   = parsed.path.rstrip("/")
    parts  = [p for p in path.split("/") if p]
    if not parts or parts[0] != "api":
        _prev_post_rules(self); return
    route = "/".join(parts[1:])
    body  = self._body()

    if route == "rules/evaluate":
        from static_rules import evaluate_transaction
        txn    = body.get("transaction", {})
        enabled= body.get("enabled_rules", None)
        result = evaluate_transaction(txn, enabled)
        self._send(result)

    elif route == "rules/batch":
        from static_rules import batch_evaluate
        txns   = body.get("transactions", [])
        enabled= body.get("enabled_rules", None)
        result = batch_evaluate(txns, enabled)
        # Strip full results for bandwidth
        result.pop("results", None)
        self._send(result)

    else:
        _prev_post_rules(self)

AMLHandler._do_get_chain  = _rules_get
AMLHandler._do_post_chain = _rules_post
